# FINAL_SAFE_REBUILD_PRESERVE_ALL_VIEWABLE.ps1
# Copy-only, no deletion, no Move-Item, no Excel COM.
# Uses Python stdlib plus ImageMagick if installed.
# Source: C:\Users\Jonathan\Downloads\5V-1A SMPS -20260704T141105Z-3-001\5V-1A SMPS
# Repo:   C:\Git\5V-1A SMPS

$ErrorActionPreference = "Stop"

function Get-PythonCommand {
    $py = Get-Command py -ErrorAction SilentlyContinue
    if ($null -ne $py) { return "py" }
    $python = Get-Command python -ErrorAction SilentlyContinue
    if ($null -ne $python) { return "python" }
    return $null
}

$PythonCmd = Get-PythonCommand
if ($null -eq $PythonCmd) {
    Write-Host "ERROR: Python not found as py or python. Install Python, then rerun." -ForegroundColor Red
    exit 1
}

$RepoRoot = "C:\Git\5V-1A SMPS"
if (-not (Test-Path -LiteralPath $RepoRoot)) {
    New-Item -ItemType Directory -Path $RepoRoot | Out-Null
}

$HelperPath = Join-Path $RepoRoot "FINAL_SAFE_REBUILD_HELPER.py"
$B64 = ""
[System.IO.File]::WriteAllBytes($HelperPath, [System.Convert]::FromBase64String($B64))

Write-Host "Running final safe rebuild helper..." -ForegroundColor Cyan
& $PythonCmd $HelperPath

if ($LASTEXITCODE -ne 0) {
    Write-Host "Helper failed with exit code $LASTEXITCODE" -ForegroundColor Red
    exit $LASTEXITCODE
}

Write-Host ""
Write-Host "Done. Review C:\Git\5V-1A SMPS, then commit:" -ForegroundColor Green
Write-Host 'cd "C:\Git\5V-1A SMPS"'
Write-Host "git status --untracked-files=all"
Write-Host "git add README.md .gitignore .gitattributes LICENSE docs hardware validation tools archive"
Write-Host 'git commit -m "Final safe rebuild with preserved archive and viewable assets"'
Write-Host "git push"
